module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output reg o_en
);

    reg [63:0] adda_reg, addb_reg;
    reg i_en_reg;
    reg [64:0] sum_reg;

    wire [63:0] adda_wire, addb_wire;
    wire [64:0] sum_wire;

    assign adda_wire = adda_reg;
    assign addb_wire = addb_reg;

    assign sum_wire = adda_wire + addb_wire + sum_reg[64];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 64'b0;
            addb_reg <= 64'b0;
            i_en_reg <= 1'b0;
            sum_reg <= 65'b0;
            o_en <= 1'b0;
        end else begin
            if (i_en_reg) begin
                adda_reg <= adda;
                addb_reg <= addb;
                i_en_reg <= 1'b0;
                sum_reg <= sum_wire;
                o_en <= 1'b1;
            end else begin
                adda_reg <= adda_reg;
                addb_reg <= addb_reg;
                i_en_reg <= i_en;
                sum_reg <= sum_reg;
                o_en <= 1'b0;
            end
        end
    end

    assign result = sum_reg;

endmodule
